# budget_recovery_projection.py — estimate when freeze will lift
from datetime import datetime, timedelta
from dataclasses import dataclass

@dataclass
class BudgetConsumptionEvent:
    timestamp: datetime
    fraction_consumed: float  # e.g., 0.30 = consumed 30% of 30-day budget

def project_budget_recovery(
    events: list[BudgetConsumptionEvent],
    window_days: int = 30,
    freeze_threshold: float = 0.25,  # 25% remaining = freeze threshold
) -> datetime | None:
    """
    Given a list of consumption events, project when the budget
    will recover above the freeze threshold.
    Returns None if budget is already above threshold.
    """
    now = datetime.utcnow()
    total_consumed = sum(e.fraction_consumed for e in events
                        if (now - e.timestamp).days < window_days)

    if 1.0 - total_consumed >= freeze_threshold:
        return None  # Not in freeze; no recovery needed

    # Find when enough events have aged out to push budget above threshold
    future_events = sorted(
        [e for e in events if (now - e.timestamp).days < window_days],
        key=lambda e: e.timestamp + timedelta(days=window_days)
    )

    running_consumed = total_consumed
    for event in future_events:
        expiry = event.timestamp + timedelta(days=window_days)
        running_consumed -= event.fraction_consumed
        if 1.0 - running_consumed >= freeze_threshold:
            return expiry

    return None  # Budget never recovers above threshold (shouldn't happen in practice)


# Example: incident on day 5 consumed 40% of budget
events = [
    BudgetConsumptionEvent(
        timestamp=datetime.utcnow() - timedelta(days=25),
        fraction_consumed=0.40,
    ),
    BudgetConsumptionEvent(
        timestamp=datetime.utcnow() - timedelta(days=10),
        fraction_consumed=0.20,
    ),
]

recovery_time = project_budget_recovery(events)
if recovery_time:
    print(f"Budget projected to recover above freeze threshold at: {recovery_time}")
else:
    print("Budget already above freeze threshold")
